                      <div style={{ color: "#dc2626", fontSize: "0.85rem", fontWeight: 700, marginTop: "0.5rem", display: "flex", alignItems: "center", gap: "0.25rem", justifyContent: "flex-end" }}>
                        <AlertCircle size={14} /> Fine: ${issue.fine}
                      </div>
