            <li className="flex items-center gap-3 text-sm p-2 sm:p-3 bg-background rounded-lg opacity-60">
              <Calendar size={16} className="flex-shrink-0" /> <span className="truncate">Quiz 1 (Unlocks Oct 15)</span>
