"use client";

import { useState, useEffect, useRef } from "react";
import { Send, Search, Phone, Video as VideoIcon, Info } from "lucide-react";
import { io, Socket } from "socket.io-client";

interface Message {
  id: string;
  senderId: string;
  text: string;
  timestamp: string;
}

export default function TeacherMessagesClient({ currentUserId, currentUserName }: any) {
  const [socket, setSocket] = useState<Socket | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState("");
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const [activeContact, setActiveContact] = useState("parent_1");

  const contacts = [
    { id: "parent_1", name: "Mr. Smith (John's Father)", role: "Parent", online: true },
    { id: "admin_1", name: "Principal Office", role: "Admin", online: false },
    { id: "teacher_2", name: "Jane Doe", role: "Colleague", online: true },
  ];

  useEffect(() => {
    // In production, this points to your real socket server path
    const newSocket = io(process.env.NEXT_PUBLIC_SOCKET_URL || "http://localhost:3000", {
      path: "/api/socket/io",
      addTrailingSlash: false,
    });
    setSocket(newSocket);

    // Simulated initial fetch
    setMessages([
      { id: "1", senderId: "parent_1", text: "Hello! John has been struggling with his homework.", timestamp: "09:00 AM" },
      { id: "2", senderId: currentUserId, text: "I can assign some extra practice sheets.", timestamp: "09:05 AM" },
    ]);

    return () => { newSocket.close(); };
  }, [currentUserId]);

  useEffect(() => {
    if (!socket) return;
    socket.on("receive-message", (message: Message) => {
      setMessages((prev) => [...prev, message]);
      scrollToBottom();
    });
    return () => { socket.off("receive-message"); };
  }, [socket]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => scrollToBottom(), [messages]);

  const sendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim() || !socket) return;

    const newMsg: Message = {
      id: Date.now().toString(),
      senderId: currentUserId,
      text: inputText,
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
    };

    setMessages((prev) => [...prev, newMsg]);
    socket.emit("send-message", newMsg);
    setInputText("");
  };

  return (
    <div className="flex-1 flex overflow-hidden bg-background">
      {/* Contact Sidebar */}
      <div className="w-80 border-r border-border flex flex-col bg-card">
        <div className="p-4 border-b border-border">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground w-4 h-4" />
            <input type="text" placeholder="Search contacts..." className="form-input pl-9 rounded-full bg-background" />
          </div>
        </div>
        <div className="flex-1 overflow-y-auto">
          {contacts.map((contact) => (
            <div 
              key={contact.id} 
              onClick={() => setActiveContact(contact.id)}
              className={`flex items-center gap-3 p-4 cursor-pointer transition-colors border-l-4 ${activeContact === contact.id ? 'bg-primary/5 border-primary' : 'border-transparent hover:bg-card-hover'}`}
            >
              <div className="relative">
                <div className="avatar w-10 h-10">{contact.name.substring(0, 2)}</div>
                {contact.online && <div className="absolute bottom-0 right-0 w-3 h-3 bg-success rounded-full border-2 border-card"></div>}
              </div>
              <div className="flex-1 min-w-0">
                <div className="font-bold text-sm truncate">{contact.name}</div>
                <div className="text-xs text-muted-foreground truncate">{contact.role}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Chat Area */}
      <div className="flex-1 flex flex-col">
        {/* Chat Header */}
        <div className="h-16 border-b border-border flex items-center justify-between px-6 bg-card">
          <div className="flex items-center gap-3">
            <div className="font-bold">{contacts.find(c => c.id === activeContact)?.name}</div>
            <span className="badge badge-success text-[10px]">Online</span>
          </div>
          <div className="flex items-center gap-4 text-muted-foreground">
            <button className="hover:text-primary transition-colors"><Phone size={18} /></button>
            <button className="hover:text-primary transition-colors"><VideoIcon size={18} /></button>
            <button className="hover:text-primary transition-colors"><Info size={18} /></button>
          </div>
        </div>

        {/* Messages List */}
        <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-background">
          {messages.map((msg) => {
            const isMe = msg.senderId === currentUserId;
            return (
              <div key={msg.id} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                <div className={`max-w-[70%] rounded-2xl px-4 py-2 ${isMe ? 'bg-primary text-primary-foreground rounded-br-sm' : 'bg-card border border-border text-card-foreground rounded-bl-sm'}`}>
                  {msg.text}
                </div>
                <div className="text-[10px] text-muted-foreground mt-1 px-1">{msg.timestamp}</div>
              </div>
            );
          })}
          <div ref={messagesEndRef} />
        </div>

        {/* Chat Input */}
        <div className="p-4 bg-card border-t border-border">
          <form onSubmit={sendMessage} className="flex gap-2 relative">
            <input 
              type="text" 
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder="Type your message..." 
              className="form-input flex-1 rounded-full pl-4 pr-12 py-3 bg-background border-transparent focus:border-primary focus:ring-1 focus:ring-primary shadow-sm"
            />
            <button 
              type="submit" 
              disabled={!inputText.trim()}
              className="absolute right-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-full bg-primary text-white disabled:opacity-50 transition-opacity"
            >
              <Send size={14} />
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/lib/auth/auth";
import { prisma } from "@/lib/db/prisma";

export const dynamic = "force-dynamic";

export async function GET(req: NextRequest) {
  try {
    const session = await auth();
    if (!session || session.user?.role !== "STUDENT") {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const userId = (session.user as any).id;
    const student = await prisma.student.findUnique({
      where: { userId },
      select: { id: true }
    });

    if (!student) {
      return NextResponse.json({ error: "Student profile not found" }, { status: 404 });
    }

    const { searchParams } = new URL(req.url);
    const month = searchParams.get('month');
    const year = searchParams.get('year');

    let whereClause: any = { studentId: student.id };

    if (month && year) {
      const startDate = new Date(parseInt(year), parseInt(month), 1);
      const endDate = new Date(parseInt(year), parseInt(month) + 1, 0);
      whereClause.date = {
        gte: startDate,
        lte: endDate
      };
    }

    const records = await prisma.attendanceRecord.findMany({
      where: whereClause,
      orderBy: { date: 'desc' },
      include: {
        takenBy: { include: { user: { select: { name: true } } } }
      }
    });

    // Monthly summary
    const today = new Date();
    const currentMonthStart = new Date(today.getFullYear(), today.getMonth(), 1);
    const currentMonthEnd = new Date(today.getFullYear(), today.getMonth() + 1, 0);

    const monthlyRecords = await prisma.attendanceRecord.findMany({
      where: {
        studentId: student.id,
        date: { gte: currentMonthStart, lte: currentMonthEnd }
      }
    });

    const monthlySummary = {
      present: monthlyRecords.filter(r => r.status === 'PRESENT').length,
      absent: monthlyRecords.filter(r => r.status === 'ABSENT').length,
      late: monthlyRecords.filter(r => r.status === 'LATE').length,
      excused: monthlyRecords.filter(r => r.status === 'EXCUSED').length,
      total: monthlyRecords.length
    };

    // Overall percentage (Academic Year)
    const overallRecords = await prisma.attendanceRecord.count({ where: { studentId: student.id } });
    const presentRecords = await prisma.attendanceRecord.count({ 
      where: { 
        studentId: student.id, 
        status: { in: ['PRESENT', 'LATE', 'EXCUSED'] } 
      } 
    });

    const overallPercentage = overallRecords > 0 ? (presentRecords / overallRecords) * 100 : 100;

    return NextResponse.json({ 
      records, 
      monthlySummary, 
      overallPercentage: overallPercentage.toFixed(1) 
    });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/lib/auth/auth";
import { prisma } from "@/lib/db/prisma";

export const dynamic = "force-dynamic";

export async function GET(req: NextRequest) {
  try {
    const session = await auth();
    if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const tenantId = session.user?.tenantId as string;
    const role = session.user?.role as string;
    const { searchParams } = new URL(req.url);
    const month = searchParams.get("month"); // e.g. "2026-04"
    const year = searchParams.get("year");

    let whereClause: any = { tenantId };

    // Date range filtering
    if (month) {
      const [y, m] = month.split("-").map(Number);
      whereClause.startDate = { gte: new Date(y, m - 1, 1) };
      whereClause.endDate = { lte: new Date(y, m, 0, 23, 59, 59) };
    } else if (year) {
      whereClause.startDate = { gte: new Date(Number(year), 0, 1) };
      whereClause.endDate = { lte: new Date(Number(year), 11, 31, 23, 59, 59) };
    }

    const events = await prisma.event.findMany({
      where: whereClause,
      orderBy: { startDate: "asc" },
    });

    // Filter events based on role for non-admins
    const filteredEvents = events.filter((ev) => {
      if (role === "ADMIN" || role === "SUPER_ADMIN") return true;

      let targetRoles: string[] = [];
      try {
        targetRoles = typeof ev.targetRoles === "string" ? JSON.parse(ev.targetRoles) : (ev.targetRoles as string[]);
      } catch { targetRoles = []; }

      if (!Array.isArray(targetRoles) || targetRoles.length === 0 || targetRoles.includes("ALL")) return true;

      if (role === "STUDENT" && targetRoles.includes("STUDENT")) return true;
      if (role === "TEACHER" && targetRoles.includes("TEACHER")) return true;
      if (role !== "STUDENT" && role !== "TEACHER" && targetRoles.includes("STAFF")) return true;

      return false;
    });

    return NextResponse.json({ events: filteredEvents });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

export async function POST(req: NextRequest) {
  try {
    const session = await auth();
    if (!session || !["ADMIN", "SUPER_ADMIN"].includes(session.user?.role as string)) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }
    const tenantId = session.user?.tenantId as string;
    const body = await req.json();

    const { title, description, eventType, startDate, endDate, allDay, targetRoles } = body;

    if (!title || !eventType || !startDate || !endDate) {
      return NextResponse.json({ error: "Title, event type, start date, and end date are required" }, { status: 400 });
    }

    const event = await prisma.event.create({
      data: {
        tenantId,
        title,
        description: description || null,
        eventType,
        startDate: new Date(startDate),
        endDate: new Date(endDate),
        allDay: allDay !== undefined ? allDay : true,
        targetRoles: JSON.stringify(targetRoles || ["ALL"]),
      },
    });

    return NextResponse.json({ success: true, event });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/lib/auth/auth";
import { prisma } from "@/lib/db/prisma";

export const dynamic = "force-dynamic";

export async function GET(req: NextRequest) {
  try {
    const session = await auth();
    if (!session || !["ADMIN", "SUPER_ADMIN"].includes(session.user?.role as string)) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const tenantId = session.user?.tenantId as string;
    const { searchParams } = new URL(req.url);
    const gradeId = searchParams.get("gradeId");
    const sectionId = searchParams.get("sectionId");
    const examScheduleId = searchParams.get("examScheduleId");

    // Build the student filter via enrollments
    let studentIds: string[] | undefined;

    if (sectionId) {
      const enrollments = await prisma.enrollment.findMany({
        where: { tenantId, sectionId, status: "ACTIVE" },
        select: { studentId: true },
      });
      studentIds = enrollments.map((e) => e.studentId);
    } else if (gradeId) {
      // Get all sections for this grade, then their enrollments
      const sections = await prisma.section.findMany({
        where: { tenantId, gradeId, deletedAt: null },
        select: { id: true },
      });
      const sectionIds = sections.map((s) => s.id);
      const enrollments = await prisma.enrollment.findMany({
        where: { tenantId, sectionId: { in: sectionIds }, status: "ACTIVE" },
        select: { studentId: true },
      });
      studentIds = enrollments.map((e) => e.studentId);
    }

    let gradeRecordWhere: any = { tenantId };
    if (studentIds !== undefined) {
      gradeRecordWhere.studentId = { in: studentIds };
    }
    if (examScheduleId) {
      gradeRecordWhere.exam = { examScheduleId };
    }

    const gradeRecords = await prisma.gradeRecord.findMany({
      where: gradeRecordWhere,
      include: {
        student: {
          include: {
            user: { select: { name: true } },
            enrollments: {
              where: { status: "ACTIVE" },
              include: { section: { include: { grade: true } } },
            },
          },
        },
        subject: { select: { id: true, name: true, code: true } },
        exam: {
          select: {
            id: true,
            totalMarks: true,
            examSchedule: { select: { id: true, name: true, type: true } },
          },
        },
      },
      orderBy: { createdAt: "desc" },
    });

    return NextResponse.json({ gradeRecords });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

export async function POST(req: NextRequest) {
  try {
    const session = await auth();
    if (!session || !["ADMIN", "SUPER_ADMIN"].includes(session.user?.role as string)) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const tenantId = session.user?.tenantId as string;
    const body = await req.json();

    // Support bulk upsert: body.records = [{ studentId, subjectId, examId, marksObtained, totalMarks, grade, remarks }]
    const { records } = body;

    if (!Array.isArray(records) || records.length === 0) {
      return NextResponse.json({ error: "records array is required" }, { status: 400 });
    }

    const results = [];
    for (const rec of records) {
      const { studentId, subjectId, examId, marksObtained, totalMarks, grade, remarks } = rec;

      if (!studentId || !subjectId || marksObtained === undefined || !totalMarks) {
        continue; // Skip invalid records
      }

      // Upsert: find existing or create
      const existing = await prisma.gradeRecord.findFirst({
        where: { tenantId, studentId, subjectId, examId: examId || null },
      });

      if (existing) {
        const updated = await prisma.gradeRecord.update({
          where: { id: existing.id },
          data: {
            marksObtained: parseFloat(marksObtained),
            totalMarks: parseFloat(totalMarks),
            grade: grade || null,
            remarks: remarks || null,
          },
        });
        results.push(updated);
      } else {
        const created = await prisma.gradeRecord.create({
          data: {
            tenantId,
            studentId,
            subjectId,
            examId: examId || null,
            marksObtained: parseFloat(marksObtained),
            totalMarks: parseFloat(totalMarks),
            grade: grade || null,
            remarks: remarks || null,
          },
        });
        results.push(created);
      }
    }

    return NextResponse.json({ success: true, count: results.length, results });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/lib/auth/auth";
import { prisma } from "@/lib/db/prisma";

export const dynamic = "force-dynamic";

export async function GET(req: NextRequest) {
  try {
    const session = await auth();
    if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const tenantId = session.user?.tenantId as string;
    const { searchParams } = new URL(req.url);
    const sectionId = searchParams.get('sectionId');
    const role = session.user?.role;

    let whereClause: any = { tenantId };

    if (sectionId) {
      whereClause.sectionId = sectionId;
    }

    // Role-based filtering
    if (role === 'TEACHER') {
      const userId = (session.user as any)?.id;
      if (!userId) return NextResponse.json({ error: "Missing User ID in session" }, { status: 401 });

      const staff = await prisma.staff.findUnique({ where: { userId } });
      if (staff) {
        whereClause.staffId = staff.id;
      } else {
        return NextResponse.json({ slots: [] });
      }
    } else if (role === 'STUDENT') {
      const userId = (session.user as any)?.id;
      if (!userId) return NextResponse.json({ error: "Missing User ID in session" }, { status: 401 });

      const student = await prisma.student.findUnique({ 
        where: { userId },
        include: { enrollments: { where: { status: 'ACTIVE' } } }
      });
      if (student && student.enrollments.length > 0) {
        whereClause.sectionId = student.enrollments[0].sectionId;
      } else {
        return NextResponse.json({ slots: [] });
      }
    }

    const slots = await prisma.timetableSlot.findMany({
      where: whereClause,
      include: {
        section: { 
          include: { 
            grade: true,
            classTeacher: { include: { user: { select: { name: true } } } }
          } 
        },
        subject: true,
        staff: { include: { user: true } }
      },
      orderBy: [
        { dayOfWeek: 'asc' },
        { startTime: 'asc' }
      ]
    });

    return NextResponse.json({ slots });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

export async function POST(req: NextRequest) {
  try {
    const session = await auth();
    if (!session || !["ADMIN", "SUPER_ADMIN"].includes(session.user?.role as string)) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }
    const tenantId = session.user?.tenantId as string;
    const body = await req.json();

    const { sectionId, subjectId, staffId, dayOfWeek, startTime, endTime, room } = body;

    if (!sectionId || !subjectId || !staffId || dayOfWeek === undefined || !startTime || !endTime) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 });
    }

    // Optional: Check for conflicts (same teacher same time, or same room same time)
    const existingTeacherSlot = await prisma.timetableSlot.findFirst({
      where: {
        tenantId, staffId, dayOfWeek: Number(dayOfWeek),
        OR: [
          { startTime: { lte: startTime }, endTime: { gt: startTime } },
          { startTime: { lt: endTime }, endTime: { gte: endTime } },
          { startTime: { gte: startTime }, endTime: { lte: endTime } }
        ]
      }
    });

    if (existingTeacherSlot) {
      return NextResponse.json({ error: "Teacher is already booked for this time slot" }, { status: 400 });
    }

    const slot = await prisma.timetableSlot.create({
      data: {
        tenantId,
        sectionId,
        subjectId,
        staffId,
        dayOfWeek: Number(dayOfWeek),
        startTime,
        endTime,
        room
      },
      include: {
        section: { 
          include: { 
            grade: true,
            classTeacher: { include: { user: { select: { name: true } } } }
          } 
        },
        subject: true,
        staff: { include: { user: true } }
      }
    });

    return NextResponse.json({ success: true, slot });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

