        .feature-pill {
          display: inline-flex; align-items: center; gap: 0.6rem;
          background: hsl(0 0% 100% / 0.07); border: 1px solid hsl(0 0% 100% / 0.1);
          padding: 0.5rem 1rem; border-radius: 999px;
